using Microsoft.EntityFrameworkCore;

// Cosmos DB project context — fixes for EF Core 9 breaking changes
class CosmosDbContext : DbContext
{
    public DbSet<Session> Sessions => Set<Session>();

    protected override void OnConfiguring(DbContextOptionsBuilder options)
    {
        options.UseCosmos(
            "AccountEndpoint=https://localhost:8081/;AccountKey=...",
            "MyDatabase");
    }

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Fix 1: EF Core 9 renamed the default discriminator from "Discriminator" to "$type".
        // Existing documents use "Discriminator", so configure it explicitly.
        modelBuilder.Entity<Session>().HasDiscriminator<string>("Discriminator");

        // Fix 2: EF Core 9 no longer embeds the discriminator in the JSON `id` property.
        // Existing documents have ids like "Session|abc-123"; preserve that format.
        modelBuilder.Entity<Session>().HasRootDiscriminatorInJsonId(true);
    }
}

class Session
{
    public string Id { get; set; } = default!;
    public string Name { get; set; } = default!;
}

// Fix 3: EF Core 9 Cosmos provider no longer supports synchronous I/O.
// All sync calls (ToList, SaveChanges, First, etc.) now throw.
// Use async equivalents instead.
class CosmosService
{
    private readonly CosmosDbContext _db;
    public CosmosService(CosmosDbContext db) => _db = db;

    // BEFORE (breaks in EF Core 9):
    //   var sessions = _db.Sessions.Where(s => s.Name == name).ToList();
    //   _db.Sessions.Add(session);
    //   _db.SaveChanges();

    // AFTER — use async equivalents:
    public async Task<List<Session>> GetSessionsAsync(string name)
    {
        return await _db.Sessions.Where(s => s.Name == name).ToListAsync();
    }

    public async Task AddSessionAsync(Session session)
    {
        _db.Sessions.Add(session);
        await _db.SaveChangesAsync();
    }
}

